import React from 'react';
import { Outlet } from 'react-router-dom';
import Header from './Header';

const DashboardLayout = () => {
  return (
      <div className="flex flex-col h-screen w-full">
        {/* Top Navbar */}
        <Header />

        {/* Main Layout */}
        <div className="flex pt-16 h-full">
          {/* Sidebar */}
          <aside className="w-64 bg-green-100 p-4 hidden md:block h-full shadow-lg">
            <ul className="space-y-3">
              <li><a href="/app/dashboard" className="block px-3 py-2 rounded bg-green-500 text-white hover:bg-green-600">Dashboard</a></li>
              <li><a href="/app/doctor-dashboard" className="block px-3 py-2 rounded bg-green-500 text-white hover:bg-green-600">Doctor Dashboard</a></li>
              <li><a href="/app/book-appointment" className="block px-3 py-2 rounded bg-green-500 text-white hover:bg-green-600">Book Appointment</a></li>
              <li><a href="/app/appointments" className="block px-3 py-2 rounded bg-green-500 text-white hover:bg-green-600">Appointment History</a></li>
              <li><a href="/app/profile" className="block px-3 py-2 rounded bg-green-500 text-white hover:bg-green-600">My Profile</a></li>
              <li><a href="/app/change-password" className="block px-3 py-2 rounded bg-green-500 text-white hover:bg-green-600">Change Password</a></li>
            </ul>
          </aside>

          {/* Main Content */}
          <main className="flex-1 p-6 bg-gray-50 overflow-y-auto">
            <Outlet />
          </main>
        </div>
      </div>
  );
};

export default DashboardLayout;
